 Texture2D Solid(Color color){var t=new Texture2D(1,1);t.SetPixel(0,0,color);t.Apply();return t;}
 Texture2D Framed(Color top,Color bottom,Color border){int size=32;var t=new Texture2D(size,size);for(int y=0;y<size;y++)for(int x=0;x<size;x++){int edge=Mathf.Min(Mathf.Min(x,size-1-x),Mathf.Min(y,size-1-y));Color c=edge<2?border:Color.Lerp(bottom,top,y/(size-1f));if(edge==2)c=Color.Lerp(c,new Color(1,.86f,.48f,1),.22f);t.SetPixel(x,y,c);}t.Apply();t.wrapMode=TextureWrapMode.Clamp;return t;}
 Texture2D AngledPanel(Color top,Color bottom,Color border,int cut=18){int w=160,h=72,b=3;var t=new Texture2D(w,h,TextureFormat.RGBA32,false);for(int y=0;y<h;y++)for(int x=0;x<w;x++){float ny=y/(h-1f);bool outer=x>=cut*(1-ny)&&x<=w-1-cut*ny;bool inner=y>=b&&y<h-b&&x>=cut*(1-ny)+b&&x<=w-1-cut*ny-b;t.SetPixel(x,y,!outer?Color.clear:inner?Color.Lerp(bottom,top,ny):border);}t.Apply();t.wrapMode=TextureWrapMode.Clamp;t.filterMode=FilterMode.Bilinear;return t;}
 void InitStyles(){if(title!=null)return;if(uiFont!=null){GUI.skin.font=uiFont;GUI.skin.label.font=uiFont;GUI.skin.button.font=uiFont;GUI.skin.box.font=uiFont;}panelTex=Framed(new Color(.15f,.20f,.145f,.94f),new Color(.075f,.105f,.075f,.94f),new Color(.38f,.27f,.12f,1));buttonTex=Framed(new Color(.28f,.34f,.23f,1),new Color(.13f,.17f,.12f,1),new Color(.52f,.36f,.14f,1));hoverTex=Framed(new Color(.58f,.52f,.27f,1),new Color(.27f,.34f,.18f,1),new Color(.94f,.72f,.28f,1));cellClearTex=Solid(new Color(0,0,0,0));GUI.skin.label.normal.textColor=ink;GUI.skin.box.normal.background=panelTex;GUI.skin.box.normal.textColor=ink;GUI.skin.box.border=new RectOffset(5,5,5,5);GUI.skin.box.padding=new RectOffset(22,22,19,19);GUI.skin.button.normal.background=buttonTex;GUI.skin.button.hover.background=hoverTex;GUI.skin.button.active.background=Framed(new Color(.72f,.50f,.18f,1),new Color(.34f,.22f,.08f,1),new Color(1,.82f,.36f,1));GUI.skin.button.border=new RectOffset(5,5,5,5);GUI.skin.button.normal.textColor=ink;GUI.skin.button.hover.textColor=Color.white;GUI.skin.button.active.textColor=Color.white;GUI.skin.button.padding=new RectOffset(14,14,9,9);title=new GUIStyle(GUI.skin.label){font=uiFont,fontSize=30,fontStyle=FontStyle.Bold,normal={textColor=new Color(1f,.88f,.48f)}};header=new GUIStyle(GUI.skin.label){font=uiFont,fontSize=20,fontStyle=FontStyle.Bold,normal={textColor=gold}};body=new GUIStyle(GUI.skin.label){font=uiFont,fontSize=14,wordWrap=true,normal={textColor=ink}};button=new GUIStyle(GUI.skin.button){font=uiFont,fontSize=15,fontStyle=FontStyle.Bold,alignment=TextAnchor.MiddleLeft,padding=new RectOffset(18,18,12,12)};card=new GUIStyle(button){fontSize=12,alignment=TextAnchor.UpperLeft,wordWrap=true,padding=new RectOffset(12,12,12,12)};cellButton=new GUIStyle(GUI.skin.button){font=uiFont,fontSize=16,fontStyle=FontStyle.Bold,alignment=TextAnchor.MiddleCenter,normal={background=cellClearTex,textColor=Color.white},hover={background=Solid(new Color(1,1,1,.16f)),textColor=Color.white},active={background=Solid(new Color(1,.82f,.35f,.28f)),textColor=Color.white}};hotspot=new GUIStyle(cellButton){fontSize=1,normal={background=cellClearTex,textColor=Color.clear}};hubLabel=new GUIStyle(GUI.skin.label){font=uiFont,fontSize=16,fontStyle=FontStyle.Bold,alignment=TextAnchor.MiddleCenter,padding=new RectOffset(12,12,7,7),normal={background=panelTex,textColor=new Color(1,.92f,.62f)}};hubLabelHover=new GUIStyle(hubLabel){normal={background=hoverTex,textColor=Color.white}};topChip=new GUIStyle(hubLabel){fontSize=14,alignment=TextAnchor.MiddleLeft};}
