 RectOffset UiSlice(Texture2D texture,float fixedArt=.42f){if(texture==null)return new RectOffset(0,0,0,0);return new RectOffset(Mathf.RoundToInt(texture.width*fixedArt),Mathf.RoundToInt(texture.width*.10f),Mathf.RoundToInt(texture.height*.16f),Mathf.RoundToInt(texture.height*.16f));}
 void ApplyIllustratedStyles(){if(illustratedStylesApplied||panelTex==null)return;illustratedStylesApplied=true;minimalButtonTex=Framed(new Color(.105f,.125f,.102f,.96f),new Color(.035f,.045f,.037f,.96f),new Color(.30f,.27f,.18f,.85f));minimalHoverTex=Framed(new Color(.20f,.24f,.18f,.98f),new Color(.065f,.085f,.065f,.98f),new Color(.78f,.61f,.28f,.95f));infoChipTex=Solid(new Color(.025f,.032f,.028f,.88f));var slice=new RectOffset(4,4,4,4);GUI.skin.button.normal.background=minimalButtonTex;GUI.skin.button.hover.background=minimalHoverTex;GUI.skin.button.active.background=minimalHoverTex;GUI.skin.button.border=slice;button.normal.background=minimalButtonTex;button.hover.background=minimalHoverTex;button.active.background=minimalHoverTex;button.border=slice;card.normal.background=panelTex;card.hover.background=minimalHoverTex;card.border=new RectOffset(5,5,5,5);navButton.normal.background=minimalButtonTex;navButton.hover.background=minimalHoverTex;navButton.border=slice;navSelected.normal.background=minimalHoverTex;navSelected.border=slice;topChip.normal.background=infoChipTex;topChip.border=new RectOffset(0,0,0,0);badge.normal.background=badgeTex;badge.border=new RectOffset(4,4,4,4);hubLabel.normal.background=infoChipTex;hubLabel.border=new RectOffset(0,0,0,0);hubLabelHover.normal.background=minimalHoverTex;hubLabelHover.border=slice;}
