 void EnsureBook(){if(bookSpread==null)bookSpread=Resources.Load<Texture2D>("Art/UI/book-spread-v1");}
 void OnGUI(){LoadIllustratedUi();EnsureBook();InitStyles();EnsureSocialStyles();EnsureHomeTextures();ApplyIllustratedStyles();TuneIllustratedText();DrawScreenBackground();Rect content=ContentRect();GUILayout.BeginArea(content);if(screen!=ScreenId.Hub)TopBar();scroll=GUILayout.BeginScrollView(scroll);switch(screen){case ScreenId.Character:CharacterScreen();break;case ScreenId.Hub:HubScreenBook();break;case ScreenId.Status:StatusScreenBook();break;case ScreenId.Vault:VaultScreen();break;case ScreenId.Faction:FactionScreenBook();break;case ScreenId.Expedition:ExpeditionScreenBook();break;case ScreenId.Pack:PackingScreen();break;case ScreenId.Map:MapScreenFiveZones();break;case ScreenId.Battle:BattleScreenCardsV2();break;case ScreenId.Reward:RewardScreen();break;case ScreenId.Shop:ShopScreen();break;case ScreenId.Event:EventScreen();break;case ScreenId.Compendium:CompendiumScreenBook();break;case ScreenId.GameOver:GameOverScreen();break;}GUILayout.EndScrollView();if(ShowBaseNavigation()&&screen!=ScreenId.Hub)BottomNavigation();GUILayout.EndArea();}
 Rect ContentRect(){if(screen==ScreenId.Hub)return new Rect(28,20,Screen.width-56,Screen.height-40);float x=Mathf.Max(58,Screen.width*.065f),y=Mathf.Max(34,Screen.height*.045f);return new Rect(x,y,Screen.width-x*2,Screen.height-y*2);}
 void ApplyDisplayFonts(){Font display=gameFont??titleFont;if(display==null)return;title.font=display;header.font=display;button.font=display;card.font=display;hubLabel.font=display;hubLabelHover.font=display;if(screenTitle!=null)screenTitle.font=display;if(navButton!=null)navButton.font=display;if(navSelected!=null)navSelected.font=display;}
 void DrawScreenBackground(){ApplyDisplayFonts();Rect full=new(0,0,Screen.width,Screen.height);GUI.color=new Color(.075f,.052f,.032f);GUI.DrawTexture(full,Texture2D.whiteTexture);GUI.color=Color.white;if(screen!=ScreenId.Hub){if(menuBackdrop!=null){GUI.color=new Color(.42f,.34f,.25f,1);GUI.DrawTexture(full,menuBackdrop,ScaleMode.ScaleAndCrop);GUI.color=Color.white;}if(bookSpread!=null&&ShowBaseNavigation()){Rect book=FitAspect(new Rect(18,12,Screen.width-36,Screen.height-24),bookSpread.width/(float)bookSpread.height);GUI.color=new Color(.72f,.67f,.56f,.82f);GUI.DrawTexture(book,bookSpread,ScaleMode.StretchToFill,true);GUI.color=Color.white;}}}
 void BeginPage(string pageTitle,string subtitle=""){GUILayout.BeginVertical();Rect banner=GUILayoutUtility.GetRect(80,68,GUILayout.ExpandWidth(true));GUI.color=new Color(.025f,.032f,.025f,.96f);GUI.DrawTexture(banner,Texture2D.whiteTexture);GUI.color=Color.white;GUI.color=new Color(.90f,.65f,.21f);GUI.DrawTexture(new Rect(banner.x,banner.y,5,banner.height),Texture2D.whiteTexture);GUI.color=Color.white;GUI.Label(new Rect(banner.x+20,banner.y+5,banner.width-40,34),pageTitle,screenTitle);if(!string.IsNullOrEmpty(subtitle))GUI.Label(new Rect(banner.x+21,banner.y+38,banner.width-42,23),subtitle,screenSubtitle);DrawOutline(banner,new Color(.42f,.31f,.14f,.8f),1);GUILayout.Space(8);GUILayout.BeginVertical(GUI.skin.box);}
 void EndPage(){GUILayout.Space(12);GUILayout.EndVertical();GUILayout.EndVertical();}
 void TopBar(){GUILayout.BeginHorizontal(GUI.skin.box,GUILayout.Height(62));GUILayout.Label("PACKSPIRE",title,GUILayout.Width(225));GUILayout.Label(ScreenLabel(screen),badge,GUILayout.Width(104),GUILayout.Height(30));GUILayout.FlexibleSpace();if(run!=null&&!ShowBaseNavigation()){GUILayout.Label($"♥ {run.hp}/{run.maxHp}",topChip,GUILayout.Width(112));GUILayout.Label($"◆ {run.gold}G",topChip,GUILayout.Width(105));GUILayout.Label(GameCatalog.Roles[run.role].name,topChip,GUILayout.Width(145));}else if(meta!=null&&meta.characterMade){GUILayout.Label($"◆ {meta.baseGold}G",topChip,GUILayout.Width(112));GUILayout.Label(GameCatalog.Roles[meta.currentRole].name,topChip,GUILayout.Width(145));GUILayout.Label(Faction(meta.currentFaction).name,topChip,GUILayout.Width(165));}GUILayout.EndHorizontal();GUILayout.Space(8);}
 bool ShowBaseNavigation()=>meta!=null&&meta.characterMade&&(screen==ScreenId.Hub||screen==ScreenId.Pack&&packingAtBase||screen==ScreenId.Expedition||screen==ScreenId.Vault||screen==ScreenId.Status||screen==ScreenId.Faction||screen==ScreenId.Compendium);
 void BottomNavigation(){GUILayout.Space(6);Rect bar=GUILayoutUtility.GetRect(100,78,GUILayout.ExpandWidth(true),GUILayout.Height(78));GUI.color=new Color(.015f,.022f,.019f,.94f);GUI.DrawTexture(bar,Texture2D.whiteTexture);GUI.color=Color.white;GUI.color=new Color(.55f,.44f,.25f,.55f);GUI.DrawTexture(new Rect(bar.x,bar.y,bar.width,1),Texture2D.whiteTexture);GUI.color=Color.white;ScreenId[] targets={ScreenId.Hub,ScreenId.Pack,ScreenId.Expedition,ScreenId.Vault,ScreenId.Status,ScreenId.Faction,ScreenId.Compendium};string[] labels={"拠点","荷造り","遠征","保管庫","役職","勢力","図鑑"};float width=bar.width/targets.Length;for(int i=0;i<targets.Length;i++){Rect item=new(bar.x+i*width,bar.y,width,bar.height);bool selected=screen==targets[i];if(selected){GUI.color=new Color(.72f,.56f,.22f,.13f);GUI.DrawTexture(item,Texture2D.whiteTexture);GUI.color=new Color(.94f,.72f,.28f);GUI.DrawTexture(new Rect(item.x+18,item.yMax-3,item.width-36,3),Texture2D.whiteTexture);GUI.color=Color.white;}Texture2D icon=navIconArt!=null&&i<navIconArt.Length?navIconArt[i]:null;if(icon!=null){Rect iconRect=new(item.center.x-22,item.y+6,44,44);GUI.color=selected?Color.white:new Color(.66f,.70f,.65f,.9f);GUI.DrawTexture(iconRect,icon,ScaleMode.ScaleToFit,true);GUI.color=Color.white;}GUI.Label(new Rect(item.x+4,item.y+51,item.width-8,22),labels[i],new GUIStyle(screenSubtitle){alignment=TextAnchor.MiddleCenter,fontSize=12,normal={textColor=selected?new Color(1f,.84f,.48f):new Color(.72f,.74f,.68f)}});if(GUI.Button(item,GUIContent.none,hotspot)){if(targets[i]==ScreenId.Pack)OpenPacking();else{run=null;screen=targets[i];scroll=Vector2.zero;}}}}
 void NavButton(string label,ScreenId target){if(GUILayout.Button(label,screen==target?navSelected:navButton,GUILayout.Height(58))){if(target==ScreenId.Pack)OpenPacking();else{run=null;screen=target;scroll=Vector2.zero;}}}
 string ScreenLabel(ScreenId value)=>value==ScreenId.Hub?"拠点":value==ScreenId.Pack?"編成":value==ScreenId.Expedition?"遠征":value==ScreenId.Battle?"戦闘":value==ScreenId.Map?"探索":value==ScreenId.Vault?"保管":value==ScreenId.Status?"役職":value==ScreenId.Faction?"勢力":value==ScreenId.Compendium?"図鑑":"MENU";
 void Character(){BeginPage("キャラクター作成","探索者の外見を選択してください。体格や髪型による能力差はありません。");GUILayout.BeginHorizontal();GUILayout.BeginVertical(GUILayout.Width(520));GUILayout.Label("体格",header);for(int i=0;i<4;i++){int n=i;string label=$"{(i<2?"男性":"女性")}タイプ {(i%2)+1}";if(GUILayout.Button(meta.body==i?$"● {label}":$"○ {label}",button,GUILayout.Height(54)))meta.body=n;}GUILayout.Space(18);GUILayout.Label("髪型",header);string[] hair={"短髪","ミディアム","結び髪"};for(int i=0;i<3;i++){int n=i;if(GUILayout.Button(meta.hair==i?$"● {hair[i]}":$"○ {hair[i]}",button,GUILayout.Height(54)))meta.hair=n;}GUILayout.Space(24);if(GUILayout.Button($"この姿で始める　{(meta.body<2?"男性":"女性")}／{hair[meta.hair]}",button,GUILayout.Height(68))){meta.characterMade=true;SaveSystem.Save(meta);screen=ScreenId.Hub;}GUILayout.EndVertical();GUILayout.Space(32);Rect preview=GUILayoutUtility.GetRect(520,650,GUILayout.ExpandWidth(true));GUI.DrawTexture(preview,panelTex,ScaleMode.StretchToFill);DrawCharacter(preview,meta.body,meta.hair);GUILayout.EndHorizontal();EndPage();}
 void Hub(){GUILayout.Label($"{Faction(meta.currentFaction).name}の拠点",header);float height=Mathf.Max(620,(Screen.width-82)*9f/16f);Rect art=GUILayoutUtility.GetRect(100,height,GUILayout.ExpandWidth(true));if(hubArt!=null)GUI.DrawTexture(art,hubArt,ScaleMode.ScaleAndCrop);else{GUI.color=new Color(.18f,.15f,.1f);GUI.DrawTexture(art,Texture2D.whiteTexture);GUI.color=Color.white;}Rect hero=new(art.center.x-art.width*.105f,art.y+art.height*.43f,art.width*.21f,art.width*.21f);DrawCharacter(hero,meta.body,meta.hair);hubHover="";HubHotspot(art,new Rect(.02f,.17f,.27f,.42f),"鍛冶場",ScreenId.Vault);HubHotspot(art,new Rect(.01f,.57f,.28f,.38f),"荷造り",ScreenId.Pack);HubHotspot(art,new Rect(.37f,.03f,.25f,.39f),"遠征門",ScreenId.Expedition);HubHotspot(art,new Rect(.75f,.20f,.23f,.36f),"保管庫",ScreenId.Vault);HubHotspot(art,new Rect(.72f,.55f,.27f,.42f),"酒場・図鑑",ScreenId.Compendium);HubHotspot(art,new Rect(.57f,.04f,.24f,.38f),"勢力会館",ScreenId.Faction);HubHotspot(art,new Rect(.39f,.45f,.22f,.43f),GameCatalog.Roles[meta.currentRole].name,ScreenId.Status);}
 Rect FitAspect(Rect target,float aspect){float width=target.width,height=width/Mathf.Max(.01f,aspect);if(height>target.height){height=target.height;width=height*aspect;}return new Rect(target.center.x-width*.5f,target.center.y-height*.5f,width,height);}
 void DrawCharacter(Rect target,int bodyIndex,int hairIndex){if(characterArt==null)return;int col=Mathf.Clamp(bodyIndex,0,3),row=Mathf.Clamp(hairIndex,0,2);Rect uv=new(col*.25f,(2-row)/3f,.25f,1f/3f);float aspect=(uv.width*characterArt.width)/(uv.height*characterArt.height);GUI.DrawTextureWithTexCoords(FitAspect(target,aspect),characterArt,uv,true);}
 void HubHotspot(Rect parent,Rect normalized,string label,ScreenId next){Rect r=new(parent.x+parent.width*normalized.x,parent.y+parent.height*normalized.y,parent.width*normalized.width,parent.height*normalized.height);bool hovered=r.Contains(UnityEngine.Event.current.mousePosition);if(hovered)hubHover=label;if(GUI.Button(r,GUIContent.none,hotspot)){if(next==ScreenId.Pack)OpenPacking();else screen=next;}float labelWidth=Mathf.Clamp(r.width*.72f,120,230);Rect plaque=new(r.center.x-labelWidth*.5f,r.yMax-42,labelWidth,36);GUI.Label(plaque,label,hovered?hubLabelHover:hubLabel);}
 void OpenPacking(){run=LoadoutSystem.CreateRun(meta,"");packingAtBase=true;selectedUid="";message="荷造りセットを編集";screen=ScreenId.Pack;}
 void HubButton(string name,string desc,ScreenId next){if(GUILayout.Button($"{name}\n{desc}",button,GUILayout.Height(110)))screen=next;}
 void Status(){Back();BeginPage("役職ステータス",$"現在職：{GameCatalog.Roles[meta.currentRole].name}");foreach(var level in meta.jobLevels.Where(x=>x.value>0)){var r=GameCatalog.Roles[level.id];GUILayout.BeginVertical(GUI.skin.box);GUILayout.Label($"{r.name}　Lv.{level.value}/{r.maxLevel}",header);GUILayout.Label(r.description,body);GUILayout.Label("Lv.7・最大レベルで専用効果候補を解禁",body);GUILayout.EndVertical();}EndPage();}
 void StatusScreen(){Back();BeginPage("役職ステータス",$"現在職：{GameCatalog.Roles[meta.currentRole].name}");GUILayout.BeginHorizontal();GUILayout.BeginVertical(GUI.skin.box,GUILayout.Width(390));Rect portrait=GUILayoutUtility.GetRect(340,430,GUILayout.ExpandWidth(true));DrawRoleArt(portrait,meta.currentRole);DrawOutline(portrait,gold,3);var current=GameCatalog.Roles[meta.currentRole];GUILayout.Label(current.name,header);GUILayout.Label(current.kind+"\n"+current.description,body);GUILayout.EndVertical();GUILayout.Space(14);GUILayout.BeginVertical(GUILayout.ExpandWidth(true));foreach(var level in meta.jobLevels.Where(x=>x.value>0)){var r=GameCatalog.Roles[level.id];GUILayout.BeginHorizontal(GUI.skin.box,GUILayout.Height(92));Rect icon=GUILayoutUtility.GetRect(72,72,GUILayout.Width(72),GUILayout.Height(72));DrawRoleArt(icon,r.id);DrawOutline(icon,level.id==meta.currentRole?gold:new Color(.38f,.31f,.18f),2);GUILayout.BeginVertical();GUILayout.Label($"{r.name}   Lv.{level.value}/{r.maxLevel}",header);GUILayout.Label(r.description,body);float progress=Mathf.Clamp01(level.value/(float)r.maxLevel);Rect bar=GUILayoutUtility.GetRect(200,9,GUILayout.Height(9));GUI.color=new Color(.05f,.06f,.045f);GUI.DrawTexture(bar,Texture2D.whiteTexture);GUI.color=new Color(.76f,.55f,.20f);GUI.DrawTexture(new Rect(bar.x,bar.y,bar.width*progress,bar.height),Texture2D.whiteTexture);GUI.color=Color.white;GUILayout.EndVertical();GUILayout.EndHorizontal();}GUILayout.EndVertical();GUILayout.EndHorizontal();EndPage();}
 void VaultScreen(){Back();var active=LoadoutSystem.Active(meta);BeginPage("保管庫",$"保管装備 {meta.stash.Count}個　／　使用中 {active.name}");GUILayout.Label("荷造りセット",header);GUILayout.BeginHorizontal();foreach(var loadout in meta.loadouts)if(GUILayout.Button(loadout.id==meta.selectedLoadoutId?$"● {loadout.name}":loadout.name,button,GUILayout.Height(48)))LoadoutSystem.Select(meta,loadout.id);GUILayout.EndHorizontal();GUILayout.Label("バックパック",header);GUILayout.BeginHorizontal();foreach(var bag in GameCatalog.Backpacks)if(GUILayout.Button(active.backpack==bag.id?$"● {bag.name}":bag.name,button,GUILayout.Height(48))){active.backpack=bag.id;meta.selectedBackpack=bag.id;}GUILayout.EndHorizontal();GUILayout.Space(14);GUILayout.BeginHorizontal();GUILayout.BeginVertical(GUI.skin.box);GUILayout.Label("装備一覧",header);DrawStashTiles();GUILayout.EndVertical();GUILayout.Space(14);GUILayout.BeginVertical(GUI.skin.box,GUILayout.Width(380));DrawStashDetail();GUILayout.EndVertical();GUILayout.EndHorizontal();EndPage();SaveSystem.Save(meta);}
 void DrawStashTiles(){for(int start=0;start<meta.stash.Count;start+=7){GUILayout.BeginHorizontal();for(int offset=0;offset<7;offset++){int index=start+offset;if(index>=meta.stash.Count){GUILayout.Space(98);continue;}var item=meta.stash[index];Rect r=GUILayoutUtility.GetRect(98,98,GUILayout.Width(98),GUILayout.Height(98));GUI.color=selectedUid==item.uid?new Color(1,.82f,.34f):Color.white;DrawItemArt(r,item.templateId);GUI.color=Color.white;DrawOutline(r,item.uid==meta.selectedHeirloomUid?gold:selectedUid==item.uid?new Color(1,.82f,.34f):new Color(.46f,.36f,.20f),item.uid==meta.selectedHeirloomUid?4:2);if(GUI.Button(r,GUIContent.none,hotspot))selectedUid=item.uid;}GUILayout.EndHorizontal();GUILayout.Space(6);}}
 void DrawStashDetail(){var item=meta.stash.FirstOrDefault(x=>x.uid==selectedUid);GUILayout.Label("装備詳細",header);if(item==null){GUILayout.Label("装備アイコンを選択してください。",body);return;}var def=GameCatalog.Items[item.templateId];Rect art=GUILayoutUtility.GetRect(180,180,GUILayout.ExpandWidth(false));DrawItemArt(art,item.templateId);DrawOutline(art,item.uid==meta.selectedHeirloomUid?gold:TypeColor(def.type),3);GUILayout.Label(def.name,header);GUILayout.Label(def.description,body);GUILayout.Label($"{ItemTypeName(def.type)}　{def.cells.Length}マス\n耐久 {item.durability}/6　鍛錬 +{item.temper}\n使用 {item.uses}回　傷跡 {item.scars.Count}",body);if(!string.IsNullOrEmpty(def.linkRule)){GUILayout.Label("LINK",header);GUILayout.Label(def.linkRule,body);}GUILayout.Space(10);if(GUILayout.Button(item.uid==meta.selectedHeirloomUid?"★ 家宝に設定中":"家宝に設定",button,GUILayout.Height(48)))meta.selectedHeirloomUid=item.uid;int price=30*(item.temper+1);GUI.enabled=meta.baseGold>=price&&item.temper<5;if(GUILayout.Button($"{price}Gで鍛錬",button,GUILayout.Height(48))){meta.baseGold-=price;item.temper++;}GUI.enabled=true;}
 void Vault(){Back();var active=LoadoutSystem.Active(meta);BeginPage($"保管庫　{meta.stash.Count}個",$"使用中：{active.name} / {GameCatalog.Backpacks.First(x=>x.id==active.backpack).name}");GUILayout.Label("荷造りセット",header);GUILayout.BeginHorizontal();foreach(var loadout in meta.loadouts){if(GUILayout.Button(loadout.id==meta.selectedLoadoutId?$"● {loadout.name}":loadout.name,button,GUILayout.Height(50)))LoadoutSystem.Select(meta,loadout.id);}GUILayout.EndHorizontal();GUILayout.Space(12);GUILayout.Label("バックパック",header);GUILayout.BeginHorizontal();foreach(var bag in GameCatalog.Backpacks){if(GUILayout.Button(active.backpack==bag.id?$"● {bag.name}":bag.name,button,GUILayout.Height(55))){active.backpack=bag.id;meta.selectedBackpack=bag.id;}}GUILayout.EndHorizontal();GUILayout.Space(12);GUILayout.Label("保管装備",header);foreach(var item in meta.stash){var d=GameCatalog.Items[item.templateId];GUILayout.BeginHorizontal(GUI.skin.box);GUILayout.Label($"{(item.uid==meta.selectedHeirloomUid?"★ ":"")}{d.name} +{item.temper}　耐久{item.durability}/6　使用{item.uses}",body);if(GUILayout.Button("家宝",button,GUILayout.Width(100)))meta.selectedHeirloomUid=item.uid;if(GUILayout.Button("鍛錬",button,GUILayout.Width(100))&&meta.baseGold>=30*(item.temper+1)){meta.baseGold-=30*(item.temper+1);item.temper=Mathf.Min(5,item.temper+1);}GUILayout.EndHorizontal();}EndPage();SaveSystem.Save(meta);}
 void Faction(){Back();BeginPage("勢力関係図","所属変更には20Gが必要です。片方へ肩入れすると、競合勢力との関係にも影響します。");foreach(var f in GameCatalog.Factions){float rep=meta.factionRep.First(x=>x.id==f.id).value;GUILayout.BeginHorizontal(GUI.skin.box);GUILayout.Label($"{f.name}\n貢献 {rep:0}　{f.description}",body,GUILayout.Height(58));if(GUILayout.Button(meta.currentFaction==f.id?"● 所属中":"20Gで所属",button,GUILayout.Width(140),GUILayout.Height(58))&&meta.currentFaction!=f.id&&meta.baseGold>=20){meta.baseGold-=20;meta.currentFaction=f.id;SaveSystem.Save(meta);}GUILayout.EndHorizontal();}EndPage();}
 void Expedition(){Back();BeginPage("遠征準備","使用する荷造りセットと遠征先を選択してください。");GUILayout.Label("荷造りセット",header);GUILayout.BeginHorizontal();foreach(var loadout in meta.loadouts){if(GUILayout.Button(loadout.id==meta.selectedLoadoutId?$"● {loadout.name}":loadout.name,button,GUILayout.Height(52)))LoadoutSystem.Select(meta,loadout.id);}GUILayout.EndHorizontal();var active=LoadoutSystem.Active(meta);GUILayout.Label($"{GameCatalog.Backpacks.First(x=>x.id==active.backpack).name} / 配置{active.slots.Count}個 / 装備カード{active.deck.Count}枚",body);GUILayout.Space(16);GUILayout.Label("遠征先",header);for(int i=0;i<GameCatalog.Dungeons.Length;i++){var d=GameCatalog.Dungeons[i];GUI.enabled=i<meta.dungeonsUnlocked;if(GUILayout.Button($"{d.name}\n{d.description}　戦闘{d.battles}回",button,GUILayout.Height(88))){StartRun(d.id);}GUI.enabled=true;}EndPage();SaveSystem.Save(meta);}
 void StartRun(string dungeon){try{message="ダンジョンを生成中…";run=LoadoutSystem.CreateRun(meta,dungeon);packingAtBase=false;map=DungeonSystem.Generate(dungeon);if(map==null||map.zones==null||map.zones.Count==0)throw new Exception("区域データを生成できませんでした");screen=ScreenId.Map;selectedUid="";scroll=Vector2.zero;message=$"区域1：{DungeonSystem.CurrentZone(map).name}へ進入";}catch(Exception ex){run=null;map=null;screen=ScreenId.Expedition;message="遠征開始エラー："+ex.Message;Debug.LogException(ex);}}
 void PackingScreen(){BeginPage("荷造り","装備の外見から選び、配置・属性一致・LINK・デッキを調整します。");GUILayout.BeginHorizontal();if(GUILayout.Button(packingAtBase?"← 拠点":"← マップ",button,GUILayout.Width(120),GUILayout.Height(46)))screen=packingAtBase?ScreenId.Hub:ScreenId.Map;if(GUILayout.Button("↻ 回転",button,GUILayout.Width(110),GUILayout.Height(46)))selectedRotation=(selectedRotation+1)%4;if(GUILayout.Button("選択解除",button,GUILayout.Width(120),GUILayout.Height(46)))selectedUid="";GUILayout.FlexibleSpace();GUILayout.Label(message,body);GUILayout.EndHorizontal();GUILayout.Space(10);GUILayout.BeginHorizontal();GUILayout.BeginVertical(GUI.skin.box,GUILayout.Width(330));GUILayout.Label("保管装備",header);GUILayout.Label("アイコンを選ぶと詳細を表示",body);DrawInventoryTiles();GUILayout.EndVertical();GUILayout.Space(12);GUILayout.BeginVertical(GUI.skin.box,GUILayout.Width(520));DrawGrid();GUILayout.EndVertical();GUILayout.Space(12);GUILayout.BeginVertical(GUI.skin.box,GUILayout.Width(390));DrawItemDetail();var build=BackpackSystem.Build(run);GUILayout.Space(12);GUILayout.Label($"装備カード　{build.deck.Count-build.roleCards.Count}/8",header);foreach(var c in build.candidates){bool selected=run.selectedCardSlots.Contains(c.slotKey);GUI.enabled=selected||run.selectedCardSlots.Count<LoadoutSystem.EquipmentCardLimit;if(GUILayout.Button($"{(selected?"●":"○")} {c.name}　{c.cost}EN\n{c.text}",card,GUILayout.Height(62))){if(selected)run.selectedCardSlots.Remove(c.slotKey);else run.selectedCardSlots.Add(c.slotKey);}GUI.enabled=true;}if(build.links.Count>0){GUILayout.Label("発動中LINK",header);foreach(var link in build.links)GUILayout.Label("◆ "+link,body);}GUILayout.EndVertical();GUILayout.EndHorizontal();GUILayout.Space(12);if(GUILayout.Button("この荷造りを保存",button,GUILayout.Height(58))){LoadoutSystem.Capture(meta,run);SaveSystem.Save(meta);screen=packingAtBase?ScreenId.Hub:ScreenId.Map;}EndPage();}
 void DrawInventoryTiles(){for(int start=0;start<run.inventory.Count;start+=3){GUILayout.BeginHorizontal();for(int offset=0;offset<3;offset++){int index=start+offset;if(index>=run.inventory.Count){GUILayout.Space(92);continue;}var item=run.inventory[index];bool placed=run.placements.Any(x=>x.itemUid==item.uid),selected=selectedUid==item.uid;Rect r=GUILayoutUtility.GetRect(92,92,GUILayout.Width(92),GUILayout.Height(92));GUI.color=selected?new Color(1,.82f,.34f,1):placed?new Color(.62f,.68f,.58f,.72f):Color.white;DrawItemArt(r,item.templateId);GUI.color=Color.white;if(selected)DrawOutline(r,gold,3);else DrawOutline(r,placed?new Color(.43f,.66f,.42f):new Color(.46f,.36f,.20f),2);if(placed)GUI.Label(new Rect(r.xMax-27,r.y+4,23,23),"✓",hubLabel);if(GUI.Button(r,GUIContent.none,hotspot)){selectedUid=item.uid;selectedRotation=run.placements.FirstOrDefault(x=>x.itemUid==item.uid)?.rotation??0;message=GameCatalog.Items[item.templateId].name+"を選択";}}GUILayout.EndHorizontal();GUILayout.Space(5);}}
 void DrawItemDetail(){var item=run.inventory.FirstOrDefault(x=>x.uid==selectedUid);GUILayout.Label("装備詳細",header);if(item==null){GUILayout.Label("左の装備アイコンを選択してください。",body);return;}var def=GameCatalog.Items[item.templateId];Rect art=GUILayoutUtility.GetRect(150,150,GUILayout.ExpandWidth(false));DrawItemArt(art,item.templateId);DrawOutline(art,TypeColor(def.type),3);GUILayout.Label(def.name,header);GUILayout.Label(def.description,body);GUILayout.Space(6);GUILayout.Label($"分類　{ItemTypeName(def.type)}\n形状　{def.cells.Length}マス\n耐久　{item.durability}/6\n鍛錬　+{item.temper}",body);GUILayout.Space(6);GUILayout.Label("属性　"+string.Join("・",def.cells.Select((c,i)=>ElementLabel(item.colors!=null&&i<item.colors.Count?item.colors[i]:c.element))),body);if(!string.IsNullOrEmpty(item.traitId))GUILayout.Label("個体特性　"+item.traitId,body);if(!string.IsNullOrEmpty(def.linkRule)){GUILayout.Label("LINK",header);GUILayout.Label(def.linkRule,body);}GUILayout.Label("生成カード",header);foreach(var id in def.cardIds??new[]{def.cardId})if(GameCatalog.Cards.TryGetValue(id,out var c))GUILayout.Label($"◆ {c.name}　{c.cost}EN\n　{c.text}",body);}
 void DrawItemArt(Rect target,string itemId){if(equipmentArt==null)return;GUI.DrawTextureWithTexCoords(target,equipmentArt,ItemArtUV(itemId),true);}
 void DrawItemArtCell(Rect target,string itemId,int cellX,int cellY,int width,int height){if(equipmentArt==null)return;Rect source=ItemArtUV(itemId);Rect uv=new(source.x+source.width*cellX/width,source.y+source.height*(height-1-cellY)/height,source.width/width,source.height/height);GUI.DrawTextureWithTexCoords(target,equipmentArt,uv,true);}
 Rect ItemArtUV(string itemId){int index=ItemArtIndex(itemId),col=index%4,row=index/4;return new Rect(col*.25f,(2-row)/3f,.25f,1f/3f);}
 void DrawDungeonArt(Rect target,string dungeon){if(dungeonArt==null)return;Rect uv=dungeon=="hollow_archive"?new Rect(.5f,.5f,.5f,.5f):dungeon=="ash_forge"?new Rect(.5f,0,.5f,.5f):new Rect(0,.5f,.5f,.5f);GUI.DrawTextureWithTexCoords(target,dungeonArt,uv,true);}
 int ItemArtIndex(string id)=>id=="sword"?0:id=="shield"?1:id=="ember"?2:id=="herb"?3:id=="dagger"?4:id=="plate"?5:id=="crystal"?6:id=="bomb"?7:id=="spear"?8:id=="buckler"?9:id=="flask"?10:id=="charm"?11:0;
 void DrawOutline(Rect r,Color color,float thickness){GUI.color=color;GUI.DrawTexture(new Rect(r.x,r.y,r.width,thickness),Texture2D.whiteTexture);GUI.DrawTexture(new Rect(r.x,r.yMax-thickness,r.width,thickness),Texture2D.whiteTexture);GUI.DrawTexture(new Rect(r.x,r.y,thickness,r.height),Texture2D.whiteTexture);GUI.DrawTexture(new Rect(r.xMax-thickness,r.y,thickness,r.height),Texture2D.whiteTexture);GUI.color=Color.white;}
 string ItemTypeName(ItemType type)=>type==ItemType.Weapon?"武器":type==ItemType.Armor?"防具":type==ItemType.Rune?"ルーン":"消耗品";
 void Pack(){GUILayout.BeginHorizontal();if(GUILayout.Button(packingAtBase?"← 拠点":"← マップ",GUILayout.Width(100)))screen=packingAtBase?ScreenId.Hub:ScreenId.Map;if(GUILayout.Button("↻ 回転",GUILayout.Width(100)))selectedRotation=(selectedRotation+1)%4;if(GUILayout.Button("選択を外す",GUILayout.Width(110)))selectedUid="";GUILayout.Label(message,body);GUILayout.EndHorizontal();GUILayout.BeginHorizontal();GUILayout.BeginVertical(GUILayout.Width(250));GUILayout.Label("保管装備",header);foreach(var item in run.inventory){var d=GameCatalog.Items[item.templateId];bool placed=run.placements.Any(x=>x.itemUid==item.uid);GUI.enabled=!placed;if(GUILayout.Button($"{d.name}\n{d.description}",card,GUILayout.Height(65))){selectedUid=item.uid;selectedRotation=0;}GUI.enabled=true;}GUILayout.EndVertical();GUILayout.Space(18);DrawGrid();GUILayout.Space(18);GUILayout.BeginVertical(GUILayout.Width(320));var build=BackpackSystem.Build(run);GUILayout.Label($"装備カード {build.deck.Count-build.roleCards.Count}/8　基本カード {build.roleCards.Count}",header);foreach(var c in build.candidates){bool selected=run.selectedCardSlots.Contains(c.slotKey);GUI.enabled=selected||run.selectedCardSlots.Count<LoadoutSystem.EquipmentCardLimit;if(GUILayout.Button($"{(selected?"●":"○")} {c.name} [{c.cost}]\n{c.text}\n{c.source}",card,GUILayout.Height(74))){if(selected)run.selectedCardSlots.Remove(c.slotKey);else run.selectedCardSlots.Add(c.slotKey);}GUI.enabled=true;}GUILayout.Label("発動中リンク",header);foreach(var link in build.links)GUILayout.Label("・"+link,body);GUILayout.EndVertical();GUILayout.EndHorizontal();if(GUILayout.Button("この荷造りを保存",button,GUILayout.Height(55))){LoadoutSystem.Capture(meta,run);SaveSystem.Save(meta);screen=packingAtBase?ScreenId.Hub:ScreenId.Map;}}
void DrawGrid(){GUILayout.BeginVertical(GUILayout.Width(500));GUILayout.Label("6×4 属性バックパック",header);GUILayout.Label("暗い収納面に宿る属性色と、装備同士の隣接LINKで効果が変化します。",body);Rect grid=GUILayoutUtility.GetRect(480,330);Rect frame=new(grid.x-12,grid.y-12,grid.width+24,grid.height+24);GUI.color=new Color(.055f,.048f,.038f,1);GUI.DrawTexture(frame,Texture2D.whiteTexture);GUI.color=Color.white;DrawOutline(frame,new Color(.48f,.34f,.15f),3);float cw=grid.width/6,ch=grid.height/4;for(int i=0;i<24;i++){Rect r=new(grid.x+(i%6)*cw+2,grid.y+(i/6)*ch+2,cw-4,ch-4);GUI.color=ElementColor(GameCatalog.Board[i]);GUI.DrawTexture(r,Texture2D.whiteTexture);GUI.color=Color.white;DrawOutline(r,new Color(.62f,.58f,.43f,.22f),1);Rect glow=new(r.x+5,r.y+5,r.width-10,r.height-10);GUI.color=ElementGlow(GameCatalog.Board[i]);GUI.DrawTexture(glow,Texture2D.whiteTexture);GUI.color=Color.white;if(GUI.Button(r,GUIContent.none,cellButton))TryPlace(i);}foreach(var p in run.placements.ToList()){var item=run.inventory.First(x=>x.uid==p.itemUid);var def=GameCatalog.Items[item.templateId];var layout=BackpackSystem.Layout(def,p.rotation,item);int pieceWidth=layout.Max(x=>x.pos.x)+1,pieceHeight=layout.Max(x=>x.pos.y)+1;foreach(var cell in layout){int index=p.anchor+cell.pos.y*6+cell.pos.x;Rect r=new(grid.x+(index%6)*cw+6,grid.y+(index/6)*ch+6,cw-12,ch-12);bool match=GameCatalog.Board[index]==cell.element;GUI.color=new Color(.08f,.07f,.055f,.92f);GUI.DrawTexture(r,Texture2D.whiteTexture);GUI.color=Color.white;DrawItemArtCell(r,item.templateId,cell.pos.x,cell.pos.y,pieceWidth,pieceHeight);GUI.color=match?new Color(1f,.79f,.31f,.13f):new Color(1,1,1,.035f);GUI.DrawTexture(r,Texture2D.whiteTexture);GUI.color=Color.white;DrawOutline(r,match?gold:new Color(.30f,.25f,.16f),match?3:1);if(GUI.Button(r,GUIContent.none,cellButton)){selectedUid=item.uid;selectedRotation=p.rotation;if(UnityEngine.Event.current.button==1){run.placements.Remove(p);message=def.name+"を外しました";}}}}GUILayout.Space(8);GUILayout.Label("右クリック：個別に取り外す　／　選択後に回転可能",body);GUILayout.EndVertical();}
 string ElementLabel(Element e)=>e==Element.Fire?"火":e==Element.Water?"水":e==Element.Wind?"風":"土";
 void TryPlace(int cell){if(string.IsNullOrEmpty(selectedUid))return;var item=run.inventory.FirstOrDefault(x=>x.uid==selectedUid);if(item==null)return;var old=run.placements.FirstOrDefault(x=>x.itemUid==selectedUid);if(BackpackSystem.CanPlace(run,item,cell,selectedRotation,selectedUid)){if(old!=null)run.placements.Remove(old);run.placements.Add(new Placement(item.uid,cell,selectedRotation));message=GameCatalog.Items[item.templateId].name+"を配置";}else message="そこには入りません";}
 void Map(){BeginPage("ダンジョン探索",GameCatalog.Dungeons.First(x=>x.id==run.dungeon).name);GUILayout.BeginHorizontal();if(GUILayout.Button("荷造り",button,GUILayout.Width(120),GUILayout.Height(48)))screen=ScreenId.Pack;if(GUILayout.Button("入口から帰還",button,GUILayout.Width(150),GUILayout.Height(48))&&map.current==12){EndPage();FinishRun(true);return;}GUILayout.FlexibleSpace();GUILayout.Label($"警戒 {run.axes.alert:+#;-#;0}",StateStyle(run.axes.alert),GUILayout.Width(130),GUILayout.Height(48));GUILayout.Label($"崩壊 {run.axes.collapse:+#;-#;0}",StateStyle(run.axes.collapse),GUILayout.Width(130),GUILayout.Height(48));GUILayout.Label($"汚染 {run.axes.corruption:+#;-#;0}",StateStyle(run.axes.corruption),GUILayout.Width(130),GUILayout.Height(48));GUILayout.EndHorizontal();GUILayout.Space(12);Rect area=GUILayoutUtility.GetRect(720,600,GUILayout.ExpandWidth(true));DrawDungeonArt(area,run.dungeon);GUI.color=new Color(.02f,.035f,.025f,.36f);GUI.DrawTexture(area,Texture2D.whiteTexture);GUI.color=Color.white;DrawOutline(area,new Color(.65f,.48f,.20f),3);float w=area.width/6,h=area.height/6;foreach(var n in map.nodes){Rect r=new(area.x+n.x*w+16,area.y+n.y*h+16,w-32,h-32);GUI.enabled=n.revealed&&(n.id==map.current||DungeonSystem.Adjacent(map.current,n.id));GUI.backgroundColor=n.id==map.current?gold:n.visited?new Color(.25f,.35f,.25f):panel;string icon=n.type=="battle"?"⚔":n.type=="boss"?"♛":n.type=="shop"?"商":n.type=="rest"?"休":n.type=="treasure"?"宝":n.type=="event"?"？":n.type=="entrance"?"入":"・";if(GUI.Button(r,n.revealed?$"{icon}\n{NodeName(n.type)}":"？",button)){if(n.id!=map.current&&DungeonSystem.Move(map,n.id,run))EnterNode(n);}GUI.backgroundColor=Color.white;GUI.enabled=true;}EndPage();}
 GUIStyle StateStyle(int value)=>new GUIStyle(hubLabel){normal={background=buttonTex,textColor=value>=10?new Color(.95f,.45f,.35f):value<=-10?new Color(.55f,.82f,.65f):gold}};
 string NodeName(string type)=>type=="battle"?"戦闘":type=="boss"?"区域主":type=="gate"?"区域門":type=="shop"?"商人":type=="rest"?"野営":type=="treasure"?"宝物":type=="event"?"イベント":type=="entrance"?"入口":"未踏";
 void EnterNode(MapNode n){if(n.cleared&&n.type!="shop")return;if(n.type=="battle"||n.type=="boss"){StartBattle(n.type=="boss");return;}if(n.type=="gate"){message="区域門へ到達した";return;}if(n.type=="shop"){screen=ScreenId.Shop;return;}if(n.type=="event"||n.type=="treasure"){n.cleared=true;screen=ScreenId.Event;return;}if(n.type=="rest"){n.cleared=true;run.hp=Mathf.Min(run.maxHp,run.hp+12);foreach(var i in run.inventory)i.durability=6;message="野営して回復・修理した";}else n.cleared=true;}
 void StartBattle(bool boss){var dungeon=GameCatalog.Dungeons.First(x=>x.id==run.dungeon);var pool=GameCatalog.Enemies.Where(x=>boss?x.tier==3:x.tier==Mathf.Min(2,1+run.battlesWon/3)).ToArray();battle=BattleSystem.Begin(run,pool[UnityEngine.Random.Range(0,pool.Length)],dungeon.hpScale);screen=ScreenId.Battle;}
 void BattleScreen(){var dungeon=GameCatalog.Dungeons.First(x=>x.id==run.dungeon);BeginPage("戦闘",dungeon.name);GUILayout.BeginHorizontal();Rect playerPanel=GUILayoutUtility.GetRect(360,280,GUILayout.ExpandWidth(true));DrawCombatPortrait(playerPanel,true);GUILayout.Space(18);GUILayout.Label("対",title,GUILayout.Width(52),GUILayout.Height(280));GUILayout.Space(18);Rect enemyPanel=GUILayoutUtility.GetRect(360,280,GUILayout.ExpandWidth(true));DrawCombatPortrait(enemyPanel,false);GUILayout.EndHorizontal();GUILayout.Space(8);GUILayout.Label(battle.log,hubLabel,GUILayout.Height(42));if(run.consumables.Count>0){GUILayout.BeginHorizontal();GUILayout.Label("消耗品",header,GUILayout.Width(80));for(int i=0;i<run.consumables.Count;i++){int index=i;if(GUILayout.Button(ConsumableSystem.Name(run.consumables[i]),button,GUILayout.Width(120),GUILayout.Height(46))){ConsumableSystem.Use(run,battle,index);if(battle.enemyHp<=0){EndPage();WinBattle();return;}break;}}GUILayout.EndHorizontal();}GUILayout.Space(14);GUILayout.Label("手札",header);GUILayout.BeginHorizontal();for(int i=0;i<run.hand.Count;i++){int index=i;var c=run.hand[i];GUI.enabled=c.cost<=run.energy;GUI.backgroundColor=c.type==CardType.Attack?new Color(.42f,.15f,.12f):c.type==CardType.Skill?new Color(.11f,.29f,.36f):new Color(.30f,.17f,.39f);if(GUILayout.Button($"{c.cost} EN\n{c.name}\n\n{c.text}\n\n{c.source}",card,GUILayout.Width(165),GUILayout.Height(190))){if(BattleSystem.Play(run,battle,index)){GUI.backgroundColor=Color.white;EndPage();WinBattle();return;}}GUI.backgroundColor=Color.white;GUI.enabled=true;}GUILayout.EndHorizontal();GUILayout.Space(14);GUI.backgroundColor=new Color(.54f,.17f,.13f);if(GUILayout.Button("ターン終了",button,GUILayout.Width(180),GUILayout.Height(56))){GUI.backgroundColor=Color.white;if(BattleSystem.EndTurn(run,battle,dungeon.damage)){EndPage();FinishRun(false);return;}}GUI.backgroundColor=Color.white;EndPage();}
 void DrawCombatPortrait(Rect target,bool player){GUI.color=new Color(.038f,.044f,.035f,.98f);GUI.DrawTexture(target,Texture2D.whiteTexture);GUI.color=Color.white;DrawOutline(target,new Color(.52f,.37f,.16f),3);Rect art=new(target.x+8,target.y+8,target.width-16,target.height-132);if(player)DrawCharacter(art,meta.body,meta.hair);else DrawEnemyArt(art,battle.enemy.id);GUI.color=new Color(.018f,.021f,.017f,.94f);GUI.DrawTexture(new Rect(target.x+8,target.yMax-126,target.width-16,118),Texture2D.whiteTexture);GUI.color=Color.white;GUI.Label(new Rect(target.x+18,target.yMax-122,target.width-36,25),player?GameCatalog.Roles[run.role].name:battle.enemy.name,header);int hp=player?run.hp:Mathf.Max(0,battle.enemyHp),maxHp=player?run.maxHp:battle.enemyMaxHp,blockValue=player?run.block:battle.enemyBlock;DrawMeter(new Rect(target.x+18,target.yMax-92,target.width-36,18),hp/(float)Mathf.Max(1,maxHp),$"♥  {hp} / {maxHp}",new Color(.56f,.12f,.12f));DrawMeter(new Rect(target.x+18,target.yMax-69,target.width-36,16),Mathf.Clamp01(blockValue/24f),$"◈  防御 {blockValue}",new Color(.14f,.35f,.51f));if(player){GUI.Label(new Rect(target.xMax-100,target.yMax-121,78,24),$"◆ EN {run.energy}/3",body);DrawStatusIcons(new Rect(target.x+18,target.yMax-47,target.width-36,35),run.statuses);}else{int intent=battle.enemy.damages[battle.move%battle.enemy.damages.Length]+GameCatalog.Dungeons.First(x=>x.id==run.dungeon).damage;GUI.Label(new Rect(target.xMax-142,target.yMax-121,120,24),$"⚔ 次 {intent}",body);DrawStatusIcons(new Rect(target.x+18,target.yMax-47,target.width-36,35),battle.enemyStatuses);}}
 void DrawMeter(Rect rect,float value,string label,Color fill){GUI.color=new Color(.035f,.038f,.032f,1);GUI.DrawTexture(rect,Texture2D.whiteTexture);GUI.color=fill;GUI.DrawTexture(new Rect(rect.x+2,rect.y+2,(rect.width-4)*Mathf.Clamp01(value),rect.height-4),Texture2D.whiteTexture);GUI.color=Color.white;DrawOutline(rect,new Color(.56f,.47f,.29f,.7f),1);var meterStyle=new GUIStyle(body){alignment=TextAnchor.MiddleCenter,fontSize=12,fontStyle=FontStyle.Bold};GUI.Label(rect,label,meterStyle);}
 void DrawStatusIcons(Rect area,List<StatusState> statuses){if(statuses==null||statuses.Count==0){var noneStyle=new GUIStyle(body){alignment=TextAnchor.MiddleLeft,fontSize=12,normal={textColor=new Color(.62f,.64f,.57f)}};GUI.Label(area,"状態異常なし",noneStyle);return;}float x=area.x;foreach(var status in statuses.Take(7)){var def=ContentDatabase.Status(status.type);Rect chip=new(x,area.y,34,32);bool debuff=def!=null&&def.kind=="debuff";GUI.color=debuff?new Color(.42f,.12f,.16f,.95f):new Color(.12f,.36f,.22f,.95f);GUI.DrawTexture(chip,Texture2D.whiteTexture);GUI.color=Color.white;DrawOutline(chip,debuff?new Color(.78f,.29f,.31f):new Color(.31f,.72f,.43f),1);var iconStyle=new GUIStyle(body){alignment=TextAnchor.MiddleCenter,fontSize=17,fontStyle=FontStyle.Bold};GUI.Label(chip,def?.icon??"●",iconStyle);Rect count=new(chip.xMax-10,chip.yMax-13,14,14);var countStyle=new GUIStyle(body){alignment=TextAnchor.MiddleCenter,fontSize=10,fontStyle=FontStyle.Bold,normal={background=buttonTex,textColor=Color.white}};GUI.Label(count,status.amount.ToString(),countStyle);x+=42;}}
 void DrawRoleArt(Rect target,string role){if(roleArt==null)return;int index=RoleArtIndex(role),col=index%4,row=index/4;Rect uv=new(col*.25f,(2-row)/3f,.25f,1f/3f);float aspect=(uv.width*roleArt.width)/(uv.height*roleArt.height);GUI.DrawTextureWithTexCoords(FitAspect(target,aspect),roleArt,uv,true);}
 int RoleArtIndex(string role)=>role=="warrior"?0:role=="guardian"?1:role=="scout"?2:role=="artificer"?3:role=="blade_master"?4:role=="bulwark"?5:role=="hunter"?6:role=="grand_artificer"?7:role=="arsenal_lord"?8:role=="pack_saint"?9:role=="rune_weaver"?10:role=="grid_dancer"?11:role.Contains("knight")?5:role.Contains("druid")?6:role.Contains("artificer")||role.Contains("channeler")?7:0;
 void DrawEnemyArt(Rect target,string enemy){if(enemyArt==null)return;Rect uv=enemy=="sentinel"?new Rect(0,.5f,.174f,.5f):enemy=="rats"?new Rect(.174f,.5f,.172f,.5f):enemy=="porter"?new Rect(.346f,.5f,.172f,.5f):enemy=="mage"?new Rect(.518f,.5f,.172f,.5f):enemy=="beast"?new Rect(0,0,.344f,.5f):enemy=="knight"?new Rect(.344f,0,.347f,.5f):new Rect(.69f,0,.31f,1);float aspect=(uv.width*enemyArt.width)/(uv.height*enemyArt.height);GUI.DrawTextureWithTexCoords(FitAspect(target,aspect),enemyArt,uv,true);}
 void Battle(){var dungeon=GameCatalog.Dungeons.First(x=>x.id==run.dungeon);BeginPage("戦闘",dungeon.name);GUILayout.BeginHorizontal();GUILayout.BeginVertical(GUI.skin.box,GUILayout.Height(180));GUILayout.Label(GameCatalog.Roles[run.role].name,header);GUILayout.Label($"HP {run.hp}/{run.maxHp}　防御 {run.block}",body);GUILayout.Label($"エネルギー {run.energy}/3",header);GUILayout.Label(StatusText(run.statuses),body);GUILayout.EndVertical();GUILayout.Space(20);GUILayout.Label("VS",title,GUILayout.Width(70));GUILayout.Space(20);GUILayout.BeginVertical(GUI.skin.box,GUILayout.Height(180));GUILayout.Label(battle.enemy.name,header);GUILayout.Label($"HP {Mathf.Max(0,battle.enemyHp)}/{battle.enemyMaxHp}",body);GUILayout.Label($"次の行動　攻撃 {battle.enemy.damages[battle.move%battle.enemy.damages.Length]+dungeon.damage}",header);GUILayout.Label(StatusText(battle.enemyStatuses),body);GUILayout.EndVertical();GUILayout.EndHorizontal();GUILayout.Space(8);GUILayout.Label(battle.log,hubLabel,GUILayout.Height(42));if(run.consumables.Count>0){GUILayout.BeginHorizontal();GUILayout.Label("消耗品",header,GUILayout.Width(80));for(int i=0;i<run.consumables.Count;i++){int index=i;if(GUILayout.Button(ConsumableSystem.Name(run.consumables[i]),button,GUILayout.Width(110),GUILayout.Height(44))){ConsumableSystem.Use(run,battle,index);if(battle.enemyHp<=0){EndPage();WinBattle();return;}break;}}GUILayout.EndHorizontal();}GUILayout.Space(18);GUILayout.Label("手札",header);GUILayout.BeginHorizontal();for(int i=0;i<run.hand.Count;i++){int index=i;var c=run.hand[i];GUI.enabled=c.cost<=run.energy;GUI.backgroundColor=c.type==CardType.Attack?new Color(.52f,.20f,.16f):c.type==CardType.Skill?new Color(.16f,.36f,.44f):new Color(.38f,.23f,.48f);if(GUILayout.Button($"{c.cost} EN\n{c.name}\n\n{c.text}\n\n{c.source}",card,GUILayout.Width(165),GUILayout.Height(190))){if(BattleSystem.Play(run,battle,index)){GUI.backgroundColor=Color.white;EndPage();WinBattle();return;}}GUI.backgroundColor=Color.white;GUI.enabled=true;}GUILayout.EndHorizontal();GUILayout.Space(14);GUI.backgroundColor=new Color(.65f,.22f,.17f);if(GUILayout.Button("ターン終了",button,GUILayout.Width(180),GUILayout.Height(56))){GUI.backgroundColor=Color.white;if(BattleSystem.EndTurn(run,battle,dungeon.damage)){EndPage();FinishRun(false);return;}}GUI.backgroundColor=Color.white;EndPage();}
 string StatusText(List<StatusState> statuses)=>statuses==null||statuses.Count==0?"状態変化なし":string.Join("　",statuses.Select(x=>$"{ContentDatabase.Status(x.type)?.name ?? x.type} {x.amount}"));
 void WinBattle(){run.battlesWon++;run.gold+=12+run.battlesWon*3;run.hp=Mathf.Min(run.maxHp,run.hp+3);if(map!=null){var fought=map.nodes.FirstOrDefault(n=>n.id==map.current);if(fought!=null)fought.cleared=true;}if(battle.enemy.tier==3){FinishRun(true);return;}screen=ScreenId.Reward;}
 void RewardScreen(){BeginPage("戦闘報酬","戦利品を1つ選択。帰還後に鑑定され、保管庫に追加されます。");string[] pool={"dagger","plate","crystal","bomb","spear","buckler","flask","charm"};int start=(run.battlesWon*3)%pool.Length;GUILayout.BeginHorizontal();for(int i=0;i<3;i++){string id=pool[(start+i)%pool.Length];var item=GameCatalog.Items[id];Rect tile=GUILayoutUtility.GetRect(245,300,GUILayout.Width(245),GUILayout.Height(300));DrawVisualItemTile(tile,id,"未鑑定の戦利品",item.description);if(GUI.Button(tile,GUIContent.none,hotspot)){run.lootBag.Add(new ItemInstance(id){identified=false});screen=ScreenId.Map;}GUILayout.Space(14);}GUILayout.EndHorizontal();EndPage();}
 void ShopScreen(){BeginPage("行商人",$"所持金　{run.gold}G　／　購入品は未鑑定のまま戦利品袋に入ります。");GUILayout.Label("販売品",header);var stock=GameCatalog.Items.Keys.Take(5).ToArray();GUILayout.BeginHorizontal();foreach(var id in stock){var item=GameCatalog.Items[id];int price=14+item.cells.Length*4;GUILayout.BeginVertical(GUILayout.Width(205));Rect tile=GUILayoutUtility.GetRect(205,238,GUILayout.Width(205),GUILayout.Height(238));DrawVisualItemTile(tile,id,$"{price}G",item.description);GUI.enabled=run.gold>=price;if(GUILayout.Button($"{price}Gで購入",button,GUILayout.Height(48))){run.gold-=price;run.lootBag.Add(new ItemInstance(id){identified=false});}GUI.enabled=true;GUILayout.EndVertical();GUILayout.Space(9);}GUILayout.EndHorizontal();GUILayout.Space(16);if(GUILayout.Button("マップへ戻る",button,GUILayout.Width(190),GUILayout.Height(52)))screen=ScreenId.Map;EndPage();}
 void DrawVisualItemTile(Rect tile,string id,string ribbon,string description){var item=GameCatalog.Items[id];GUI.color=new Color(.055f,.062f,.048f,.96f);GUI.DrawTexture(tile,Texture2D.whiteTexture);GUI.color=Color.white;DrawOutline(tile,new Color(.48f,.35f,.17f),3);float artSize=Mathf.Min(tile.width-24,tile.height-88);Rect art=new(tile.center.x-artSize*.5f,tile.y+12,artSize,artSize);DrawItemArt(art,id);DrawOutline(art,TypeColor(item.type),2);GUI.color=new Color(.02f,.025f,.02f,.91f);GUI.DrawTexture(new Rect(tile.x+9,tile.yMax-70,tile.width-18,61),Texture2D.whiteTexture);GUI.color=Color.white;var itemNameStyle=new GUIStyle(header){fontSize=item.name.Length>=7?13:15,alignment=TextAnchor.MiddleCenter,clipping=TextClipping.Clip};GUI.Label(new Rect(tile.x+10,tile.yMax-68,tile.width-20,26),item.name,itemNameStyle);var ribbonStyle=new GUIStyle(body){fontSize=11,alignment=TextAnchor.MiddleCenter,clipping=TextClipping.Clip};GUI.Label(new Rect(tile.x+10,tile.yMax-41,tile.width-20,21),$"{ribbon}   {item.cells.Length}マス",ribbonStyle);}
 void CompendiumScreen(){Back();BeginPage("図鑑","装備・役職・敵を、説明文よりも先に外観で識別できる形にまとめています。");GUILayout.Label("装備",header);int index=0;GUILayout.BeginHorizontal();foreach(var item in GameCatalog.Items.Values){Rect tile=GUILayoutUtility.GetRect(178,218,GUILayout.Width(178),GUILayout.Height(218));DrawVisualItemTile(tile,item.id,ItemTypeName(item.type),item.description);index++;if(index%6==0){GUILayout.EndHorizontal();GUILayout.Space(8);GUILayout.BeginHorizontal();}else GUILayout.Space(7);}GUILayout.EndHorizontal();GUILayout.Space(20);GUILayout.Label("習得役職",header);index=0;GUILayout.BeginHorizontal();foreach(var role in GameCatalog.Roles.Values.Where(x=>meta.jobLevels.Any(j=>j.id==x.id&&j.value>0))){GUILayout.BeginVertical(GUI.skin.box,GUILayout.Width(190),GUILayout.Height(270));Rect portrait=GUILayoutUtility.GetRect(160,190,GUILayout.Width(160),GUILayout.Height(190));DrawRoleArt(portrait,role.id);DrawOutline(portrait,new Color(.49f,.36f,.17f),2);var roleNameStyle=new GUIStyle(header){fontSize=15,alignment=TextAnchor.MiddleCenter};GUILayout.Label(role.name,roleNameStyle,GUILayout.Height(26));GUILayout.Label(role.kind,body);GUILayout.EndVertical();index++;if(index%5==0){GUILayout.EndHorizontal();GUILayout.Space(8);GUILayout.BeginHorizontal();}else GUILayout.Space(8);}GUILayout.EndHorizontal();GUILayout.Space(20);GUILayout.Label("敵",header);index=0;GUILayout.BeginHorizontal();foreach(var enemy in GameCatalog.Enemies){GUILayout.BeginVertical(GUI.skin.box,GUILayout.Width(205),GUILayout.Height(260));Rect portrait=GUILayoutUtility.GetRect(170,170,GUILayout.Width(170),GUILayout.Height(170));GUI.color=new Color(.025f,.03f,.025f);GUI.DrawTexture(portrait,Texture2D.whiteTexture);GUI.color=Color.white;DrawEnemyArt(portrait,enemy.id);DrawOutline(portrait,new Color(.48f,.22f,.15f),2);var enemyNameStyle=new GUIStyle(header){fontSize=15,alignment=TextAnchor.MiddleCenter};GUILayout.Label(enemy.name,enemyNameStyle,GUILayout.Height(28));GUILayout.Label($"HP {enemy.hp}   危険度 {enemy.tier}",new GUIStyle(body){alignment=TextAnchor.MiddleCenter});GUILayout.EndVertical();index++;if(index%5==0){GUILayout.EndHorizontal();GUILayout.Space(8);GUILayout.BeginHorizontal();}else GUILayout.Space(8);}GUILayout.EndHorizontal();EndPage();}
 void Reward(){BeginPage("戦闘報酬","戦果を1つ選択してください。装備は帰還後に鑑定されます。");string[] pool={"dagger","plate","crystal","bomb","spear","buckler","flask","charm"};GUILayout.BeginHorizontal();foreach(var id in pool.OrderBy(_=>UnityEngine.Random.value).Take(3)){var item=GameCatalog.Items[id];GUI.backgroundColor=TypeColor(item.type);if(GUILayout.Button($"戦利品\n\n{item.name}\n{item.cells.Length}マス\n\n{item.description}",card,GUILayout.Width(240),GUILayout.Height(190))){GUI.backgroundColor=Color.white;run.lootBag.Add(new ItemInstance(id){identified=false});screen=ScreenId.Map;}}GUI.backgroundColor=Color.white;GUILayout.EndHorizontal();EndPage();}
 void Shop(){BeginPage("行商人",$"所持金　{run.gold}G");GUILayout.Label("販売品",header);foreach(var id in GameCatalog.Items.Keys.Take(5)){var item=GameCatalog.Items[id];int price=14+item.cells.Length*4;GUILayout.BeginHorizontal(GUI.skin.box);GUILayout.Label($"{item.name}\n{item.description}",body,GUILayout.Height(54));GUI.enabled=run.gold>=price;if(GUILayout.Button($"{price}Gで購入",button,GUILayout.Width(150),GUILayout.Height(54))){run.gold-=price;run.lootBag.Add(new ItemInstance(id){identified=false});}GUI.enabled=true;GUILayout.EndHorizontal();}GUILayout.Space(14);if(GUILayout.Button("マップへ戻る",button,GUILayout.Width(180),GUILayout.Height(50)))screen=ScreenId.Map;EndPage();}
 void Event(){BeginPage("記憶の揺らぎ","古塔の記憶が探索者へ選択を要求している。");GUILayout.Space(25);GUILayout.BeginHorizontal();if(GUILayout.Button("代償を支払う\n\n6HPを失い、24Gを得る",card,GUILayout.Width(260),GUILayout.Height(150))){run.hp=Mathf.Max(1,run.hp-6);run.gold+=24;screen=ScreenId.Map;}if(GUILayout.Button("残響を修復する\n\nすべての装備を修理",card,GUILayout.Width(260),GUILayout.Height(150))){foreach(var i in run.inventory)i.durability=6;screen=ScreenId.Map;}if(GUILayout.Button("立ち去る\n\n何も起こさず探索へ戻る",card,GUILayout.Width(260),GUILayout.Height(150)))screen=ScreenId.Map;GUILayout.EndHorizontal();EndPage();}
 void Compendium(){Back();BeginPage("図鑑","発見済みの装備、習得役職、遭遇した敵の記録です。");GUILayout.Label("装備",header);GUILayout.BeginHorizontal();int itemIndex=0;foreach(var i in GameCatalog.Items.Values){GUILayout.BeginVertical(GUI.skin.box,GUILayout.Width(235),GUILayout.Height(125));GUILayout.Label(i.name,header);GUILayout.Label($"{i.type} / {i.cells.Length}マス\n{i.description}",body);GUILayout.EndVertical();itemIndex++;if(itemIndex%5==0){GUILayout.EndHorizontal();GUILayout.BeginHorizontal();}}GUILayout.EndHorizontal();GUILayout.Space(18);GUILayout.Label("習得役職",header);foreach(var r in GameCatalog.Roles.Values.Where(x=>meta.jobLevels.Any(j=>j.id==x.id&&j.value>0)))GUILayout.Label($"{r.name}　｜　{r.kind}　｜　{r.description}",body);GUILayout.Space(18);GUILayout.Label("敵",header);foreach(var e in GameCatalog.Enemies)GUILayout.Label($"{e.name}　｜　HP {e.hp}　｜　危険度 {e.tier}",body);EndPage();}
 void FinishRun(bool win){if(win){meta.wins++;meta.baseGold+=run.gold;foreach(var item in run.inventory.Concat(run.lootBag)){var saved=meta.stash.FirstOrDefault(x=>x.uid==item.uid);if(saved==null)meta.stash.Add(CloneItem(item));else{saved.durability=item.durability;saved.uses=item.uses;saved.temper=item.temper;saved.scars=item.scars;saved.history=item.history;}}}else{var heir=run.inventory.FirstOrDefault(x=>x.uid==run.heirloomUid);if(heir!=null){heir.history.defeats++;heir.scars.Add(new ScarRecord{type="defeat",dungeon=run.dungeon,floor=run.battlesWon,timestamp=DateTimeOffset.UtcNow.ToUnixTimeSeconds()});var saved=meta.stash.FirstOrDefault(x=>x.uid==heir.uid);if(saved!=null){saved.scars=heir.scars;saved.history=heir.history;}}}meta.runs++;SaveSystem.Save(meta);message=win?"遠征成功。戦利品をすべて保管しました":"探索終了。戦利品と獲得ゴールドは持ち帰れません";screen=ScreenId.GameOver;}
 void GameOver(){BeginPage(run!=null&&run.hp>0?"遠征完了":"探索終了",message);GUILayout.Space(35);if(GUILayout.Button("拠点へ戻る",button,GUILayout.Width(240),GUILayout.Height(64))){run=null;screen=ScreenId.Hub;}EndPage();}
 void Back(){if(ShowBaseNavigation())return;var backStyle=new GUIStyle(button){normal={background=uiBackCard??uiActionNormal},hover={background=uiActionHover??uiBackCard??uiActionNormal},border=new RectOffset(0,0,0,0)};if(GUILayout.Button("← 拠点",backStyle,GUILayout.Width(130),GUILayout.Height(48))){run=null;screen=ScreenId.Hub;scroll=Vector2.zero;}}
