ン終了",button,GUILayout.Width(210),GUILayout.Height(58))){GUI.backgroundColor=Color.white;if(BattleSystem.EndTurn(run,battle,dungeon.damage)){EndPage();FinishRun(false);return;}}GUI.backgroundColor=Color.white;GUILayout.EndHorizontal();EndPage();}
