andmark;float nw=landmark?72:48,nh=landmark?58:44;Rect r=new(center.x-nw*.5f,center.y-nh*.5f,nw,nh);if(!n.revealed){GUI.color=new Color(.06f,.07f,.06f,.58f);GUI.DrawTexture(new Rect(center.x-8,center.y-8,16,16),Texture2D.whiteTexture);GUI.color=Color.white;continue;}bool connected=n.id==map.current||DungeonSystem.Connected(map,map.current,n.id);bool unlocked=n.id==map.current||DungeonSystem.CanMove(map,n.id);bool available=connected&&unlocked;bool lockedExit=connected&&(n.type=="gate"||n.type=="boss")&&!DungeonSystem.ExitUnlocked(map);Color nodeColor=n.id==map.current?new Color(.72f,.49f,.14f,.98f):n.cleared?new Color(.12f,.25f,.16f,.96f):MapNodeColor(n.type);GUI.color=nodeColor;GUI.DrawTexture(r,Texture2D.whiteTexture);GUI.color=Color.white;DrawOutline(r,n.id==map.current?gold:available?new Color(.77f,.63f,.30f):new Color(.31f,.30f,.25f),n.id==map.current?3:2);GUI.enabled=available;string icon=lockedExit?"×":MapNodeIcon(n.type);if(GUI.Button(r,new GUIContent(icon,$"{n.name}\n{NodeName(n.type)}"),new GUIStyle(navButton){fontSize=landmark?20:16,alignment=TextAnchor.MiddleCenter})){if(n.id!=map.current&&DungeonSystem.Move(map,n.id,run))EnterNode(n);}GUI.enabled=true;if(r.Contains(UnityEngine.Event.current.mousePosition))hovered=lockedExit?$"{n.name}　―　戦闘をあと {zone.requiredBattles-DungeonSystem.ClearedBattles(map)} 回完了すると開く":$"{n.name}　―　{NodeName(n.type)}{(n.cleared?"（探索済み）":"")}";}GUI.color=new Color(.015f,.020f,.017f,.90f);GUI.DrawTexture(new Rect(area.x+18,area.yMax-46,area.width-36,32),Texture2D.whiteTexture);GUI.color=Color.white;GUI.Label(new Rect(area.x+30,area.yMax-43,area.width-60,27),string.IsNullOrEmpty(hovered)?"地点へカーソルを合わせると詳細表示　／　石畳の道が実際に移動できる経路":hovered,centerBody);if(map.current==map.exit&&map.currentZone<map.zones.Count-1&&DungeonSystem.ExitUnlocked(map)){GUILayout.Space(14);DrawZoneTransition();}else if(!DungeonSystem.ExitUnlocked(map)){GUILayout.Space(10);GUILayout.Label($"区域門の解放条件：この区域の戦闘をあと {zone.requiredBattles-DungeonSystem.ClearedBattles(map)} 回