 void DrawZoneProgress(DungeonZone current){GUILayout.BeginHorizontal();for(int i=0;i<map.zones.Count;i++){var z=map.zones[i];Rect chip=GUILayoutUtility.GetRect(150,44,GUILayout.ExpandWidth(true),GUILayout.Height(44));GUI.color=i==map.currentZone?new Color(.45f,.31f,.10f,.98f):z.completed?new Color(.12f,.28f,.17f,.94f):new Color(.045f,.055f,.047f,.92f);GUI.DrawTexture(chip,Texture2D.whiteTexture);GUI.color=Color.white;DrawOutline(chip,i==map.currentZone?gold:z.completed?new Color(.36f,.62f,.39f):new Color(.26f,.25f,.20f),i==map.currentZone?2:1);GUI.Label(chip,$"{(z.completed?"✓":i==map.currentZone?"◆":"·")}  {i+1}. {z.name}",new GUIStyle(body){alignment=TextAnchor.MiddleCenter,fontSize=12,clipping=TextClipping.Clip});if(i<map.zones.Count-1)GUILayout.Space(7);}GUILayout.EndHorizontal();}
 void DrawZoneTransition(){GUILayout.BeginVertical(GUI.skin.box);GUILayout.Label($"区域踏破　―　次は {map.zones[map.currentZone+1].name}",header);GUILayout.Label("区域間の行動を1つ選択して先へ進みます。",body);GUILayout.BeginHorizontal();if(ZoneTransitionChoice("野営して進む","HPを8回復／全装備の耐久+1",new Color(.17f,.38f,.24f))){run.hp=Mathf.Min(run.maxHp,run.hp+8);foreach(var item in run.inventory)item.durability=Mathf.Min(6,item.durability+1);AdvanceZone();}GUILayout.Space(10);if(ZoneTransitionChoice("痕跡を消して進む","警戒-2／侵蝕+1",new Color(.15f,.30f,.40f))){run.axes.Change(-2,0,1);AdvanceZone();}GUILayout.Space(10);if(ZoneTransitionChoice("残骸を回収して進む","18G獲得／崩壊+2",new Color(.42f,.28f,.10f))){run.gold+=18;run.axes.Change(0,2,0);AdvanceZone();}GUILayout.EndHorizontal();GUILayout.EndVertical();}
 bool ZoneTransitionChoice(string label,string effect,Color color){Rect r=GUILayoutUtility.GetRect(270,82,GUILayout.MinWidth(240),GUILayout.Height(82));bool hover=r.Contains(UnityEngine.Event.current.mousePosition);GUI.color=hover?new Color(color.r+.12f,color.g+.12f,color.b+.12f,1):color;GUI.DrawTexture(r,Texture2D.whiteTexture);GUI.color=Color.white;DrawOutline(r,hover?gold:new Color(.47f,.39f,.21f),hover?3:2);GUI.Label(new Rect(r.x+15,r.y+9,r.width-30,27),label,new GUIStyle(header){fontSize=16,alignment=TextAnchor.MiddleLeft});GUI.Label(new Rect(r.x+16,r.y+42,r.width-32,25),effect,new GUIStyle(body){fontSize=12,alignment=TextAnchor.MiddleLeft});return GUI.Button(r,GUIContent.none,hotspot);}
 void AdvanceZone(){if(DungeonSystem.AdvanceZone(map)){message=$"区域 {map.currentZone+1}：{DungeonSystem.CurrentZone(map).name}へ進入";scroll=Vector2.zero;}}
 Vector2 MapPoint(Rect area,MapNode node)=>new(area.x+area.width*node.x/100f,area.y+area.height*node.y/100f);
 void DrawMapTerrain(Rect area){if(mapTerrain!=null)GUI.DrawTexture(area,mapTerrain,ScaleMode.ScaleAndCrop,true);else DrawDungeonArt(area,run.dungeon);}
 void DrawMapRoadV2(Vector2 start,Vector2 end,bool active){Vector2 delta=end-start;float length=delta.magnitude;if(length<1)return;DrawMapLineV2(start,end,new Color(.015f,.018f,.014f,.78f),30f);if(mapRoad!=null){Matrix4x4 old=GUI.matrix;GUIUtility.RotateAroundPivot(Mathf.Atan2(delta.y,delta.x)*Mathf.Rad2Deg,start);GUI.color=active?Color.white:new Color(.67f,.67f,.61f,.92f);GUI.DrawTextureWithTexCoords(new Rect(start.x,start.y-12f,length,24f),mapRoad,new Rect(0,0,Mathf.Max(1,length/150f),1),true);GUI.color=Color.white;GUI.matrix=old;}else DrawMapLineV2(start,end,new Color(.42f,.36f,.24f,.96f),18f);if(active)DrawMapLineV2(start,end,new Color(1f,.72f,.24f,.38f),3f);}
 void DrawMapLineV2(Vector2 start,Vector2 end,Color color,float width){Vector2 delta=end-start;float length=delta.magnitude;if(length<1)return;Matrix4x4 old=GUI.matrix;GUIUtility.RotateAroundPivot(Mathf.Atan2(delta.y,delta.x)*Mathf.Rad2Deg,start);GUI.color=color;GUI.DrawTexture(new Rect(start.x,start.y-width*.5f,length,width),Texture2D.whiteTexture);GUI.color=Color.white;GUI.matrix=old;}
 string MapNodeIcon(string type)=>type=="battle"?"⚔":type=="boss"?"♛":type=="gate"?"▶":type=="shop"?"◆":type=="rest"?"♥":type=="treasure"?"★":type=="event"?"?":type=="entrance"?"●":"·";
 Color MapNodeColor(string type)=>type=="battle"?new Color(.36f,.12f,.10f,.97f):type=="boss"?new Color(.43f,.08f,.08f,.98f):type=="gate"?new Color(.39f,.28f,.09f,.98f):type=="shop"?new Color(.18f,.29f,.34f,.97f):type=="rest"?new Color(.13f,.31f,.19f,.97f):type=="treasure"?new Color(.42f,.31f,.10f,.97f):type=="event"?new Color(.31f,.18f,.40f,.97f):new Color(.10f,.14f,.11f,.96f);
 void DrawAxisGauge(string label,int value,Color accent){Rect chip=GUILayoutUtility.GetRect(155,50,GUILayout.Width(155),GUILayout.Height(50));GUI.color=new Color(.035f,.043f,.034f,.96f);GUI.DrawTexture(chip,Texture2D.whiteTexture);GUI.color=Color.white;DrawOutline(chip,new Color(.40f,.31f,.17f),1);GUI.Label(new Rect(chip.x+9,chip.y+4,68,20),label,body);GUI.Label(new Rect(chip.xMax-48,chip.y+4,38,20),$"{value:+#;-#;0}",badge);Rect track=new(chip.x+9,chip.yMax-14,chip.width-18,7);GUI.color=new Color(.07f,.075f,.065f);GUI.DrawTexture(track,Texture2D.whiteTexture);float normalized=(value+15)/30f;GUI.color=accent;GUI.DrawTexture(new Rect(track.x,track.y,track.width*Mathf.Clamp01(normalized),track.height),Texture2D.whiteTexture);GUI.color=Color.white;}
 void DrawMapConnection(Rect area,MapNode a,MapNode b,float w,float h,bool visited){Vector2 start=new(area.x+(a.x+.5f)*w,area.y+(a.y+.5f)*h),end=new(area.x+(b.x+.5f)*w,area.y+(b.y+.5f)*h);Color color=visited?new Color(.78f,.58f,.23f,.85f):new Color(.55f,.57f,.45f,.45f);GUI.color=color;float midX=(start.x+end.x)*.5f;GUI.DrawTexture(new Rect(Mathf.Min(start.x,midX),start.y-2,Mathf.Abs(midX-start.x)+3,4),Texture2D.whiteTexture);GUI.DrawTexture(new Rect(midX-2,Mathf.Min(start.y,end.y),4,Mathf.Abs(end.y-start.y)+3),Texture2D.whiteTexture);GUI.DrawTexture(new Rect(Mathf.Min(midX,end.x),end.y-2,Mathf.Abs(end.x-midX)+3,4),Texture2D.whiteTexture);GUI.color=Color.white;}
 void CharacterScreen(){BeginPage("探索者の作成","外見を選択して、あなたの拠点へ進みましょう。能力差はありません。");GUILayout.BeginHorizontal();GUILayout.BeginVertical(GUI.skin.box,GUILayout.Width(470));Rect hero=GUILayoutUtility.GetRect(420,540,GUILayout.Width(420),GUILayout.Height(540));GUI.color=new Color(.035f,.043f,.034f);GUI.DrawTexture(hero,Texture2D.whiteTexture);GUI.color=Color.white;DrawCharacter(hero,meta.body,meta.hair);DrawOutline(hero,gold,3);GUI.Label(new Rect(hero.x+12,hero.yMax-48,hero.width-24,38),$"{(meta.body<2?"男性":"女性")}タイプ {(meta.body%2)+1}  ・  {new[]{"短髪","ミディアム","結び髪"}[meta.hair]}",hubLabel);GUILayout.EndVertical();GUILayout.Space(18);GUILayout.BeginVertical(GUILayout.ExpandWidth(true));GUILayout.Label("体格",header);GUILayout.BeginHorizontal();for(int i=0;i<4;i++){int value=i;Rect choice=GUILayoutUtility.GetRect(145,180,GUILayout.Width(145),GUILayout.Height(180));DrawAppearanceChoice(choice,value,meta.hair,meta.body==value,$"{(i<2?"男性":"女性")} {(i%2)+1}");if(GUI.Button(choice,GUIContent.none,hotspot))meta.body=value;GUILayout.Space(8);}GUILayout.EndHorizontal();GUILayout.Space(18);GUILayout.Label("髪型",header);GUILayout.BeginHorizontal();string[] hair={"短髪","ミディアム","結び髪"};for(int i=0;i<3;i++){int value=i;Rect choice=GUILayoutUtility.GetRect(170,190,GUILayout.Width(170),GUILayout.Height(190));DrawAppearanceChoice(choice,meta.body,value,meta.hair==value,hair[i]);if(GUI.Button(choice,GUIContent.none,hotspot))meta.hair=value;GUILayout.Space(10);}GUILayout.EndHorizontal();GUILayout.FlexibleSpace();GUI.backgroundColor=new Color(.63f,.42f,.12f);if(GUILayout.Button("この姿で始める",button,GUILayout.Height(66))){GUI.backgroundColor=Color.white;meta.characterMade=true;SaveSystem.Save(meta);screen=ScreenId.Hub;}GUI.backgroundColor=Color.white;GUILayout.EndVertical();GUILayout.EndHorizontal();EndPage();}
 void DrawAppearanceChoice(Rect rect,int bodyIndex,int hairIndex,bool selected,string label){GUI.color=new Color(.035f,.042f,.034f,.98f);GUI.DrawTexture(rect,Texture2D.whiteTexture);GUI.color=selected?Color.white:new Color(.54f,.54f,.50f);Rect art=new(rect.x+8,rect.y+7,rect.width-16,rect.height-44);DrawCharacter(art,bodyIndex,hairIndex);GUI.color=Color.white;DrawOutline(rect,selected?gold:new Color(.32f,.28f,.18f),selected?4:2);GUI.Label(new Rect(rect.x+5,rect.yMax-36,rect.width-10,30),(selected?"● ":"")+label,selected?hubLabelHover:hubLabel);}
 void EventScreen(){BeginPage("記憶の揺らぎ","古塔の残響が、探索者に三つの選択を差し出しています。");Rect scene=GUILayoutUtility.GetRect(760,270,GUILayout.ExpandWidth(true));DrawDungeonArt(scene,run.dungeon);GUI.color=new Color(.09f,.025f,.12f,.42f);GUI.DrawTexture(scene,Texture2D.whiteTexture);GUI.color=Color.white;DrawOutline(scene,new Color(.57f,.35f,.65f),3);GUI.Label(new Rect(scene.x+25,scene.yMax-62,scene.width-50,42),"空間の奥で、紫の残光が鼓動している……",hubLabel);GUILayout.Space(14);GUILayout.BeginHorizontal();if(ActionChoiceCard("♥","代償を支払う","HP -6  /  24G獲得",new Color(.48f,.14f,.16f))){run.hp=Mathf.Max(1,run.hp-6);run.gold+=24;screen=ScreenId.Map;}GUILayout.Space(12);if(ActionChoiceCard("✦","残響を修復する","全装備の耐久を回復",new Color(.16f,.39f,.34f))){foreach(var i in run.inventory)i.durability=6;screen=ScreenId.Map;}GUILayout.Space(12);if(ActionChoiceCard("←","立ち去る","変化なし  /  探索へ戻る",new Color(.24f,.27f,.24f)))screen=ScreenId.Map;GUILayout.EndHorizontal();EndPage();}
