 void GameOverScreen(){bool success=run!=null&&run.hp>0;BeginPage(success?"遠征完了":"探索終了",success?"戦利品と記録を拠点へ持ち帰ります。":"今回の探索はここで終了です。");GUILayout.BeginHorizontal();GUILayout.FlexibleSpace();GUILayout.BeginVertical(GUI.skin.box,GUILayout.Width(560));Rect emblem=GUILayoutUtility.GetRect(500,250,GUILayout.Width(500),GUILayout.Height(250));DrawDungeonArt(emblem,run?.dungeon??"old_spire");GUI.color=success?new Color(.11f,.34f,.17f,.32f):new Color(.40f,.08f,.08f,.42f);GUI.DrawTexture(emblem,Texture2D.whiteTexture);GUI.color=Color.white;DrawOutline(emblem,success?gold:new Color(.64f,.20f,.17f),4);var resultStyle=new GUIStyle(title){alignment=TextAnchor.MiddleCenter,fontSize=38};GUI.Label(emblem,success?"QUEST CLEAR":"EXPEDITION END",resultStyle);GUILayout.Space(12);GUILayout.Label(message,centerBody,GUILayout.Height(44));if(run!=null)GUILayout.Label($"戦闘勝利 {run.battlesWon}   ・   所持金 {run.gold}G   ・   戦利品 {run.lootBag.Count}",hubLabel,GUILayout.Height(42));GUILayout.Space(18);if(GUILayout.Button("拠点へ戻る",button,GUILayout.Height(62))){run=null;screen=ScreenId.Hub;scroll=Vector2.zero;}GUILayout.EndVertical();GUILayout.FlexibleSpace();GUILayout.EndHorizontal();EndPage();}
 void FactionScreen(){Back();BeginPage("勢力","勢力の拠点と恩恵を見比べて所属を選択。所属変更には20G必要です。");int index=0;GUILayout.BeginHorizontal();foreach(var faction in GameCatalog.Factions){float rep=meta.factionRep.First(x=>x.id==faction.id).value;GUILayout.BeginVertical(GUI.skin.box,GUILayout.Width(270));Rect art=GUILayoutUtility.GetRect(240,240,GUILayout.Width(240),GUILayout.Height(240));DrawFactionArt(art,faction.id);DrawOutline(art,meta.currentFaction==faction.id?gold:new Color(.43f,.31f,.16f),meta.currentFaction==faction.id?4:2);GUILayout.Label(faction.name,header);GUILayout.Label($"貢献 {rep:0}\n{faction.description}",body,GUILayout.Height(55));GUI.enabled=meta.currentFaction!=faction.id&&meta.baseGold>=20;if(GUILayout.Button(meta.currentFaction==faction.id?"● 所属中":"20Gで所属",button,GUILayout.Height(48))){meta.baseGold-=20;meta.currentFaction=faction.id;SaveSystem.Save(meta);}GUI.enabled=true;GUILayout.EndVertical();index++;if(index%4!=0)GUILayout.Space(10);}GUILayout.EndHorizontal();EndPage();}
