 void ExpeditionScreenV2(){Back();BeginPage("遠征準備","荷造りセットを確認し、遠征するダンジョンカードを選択してください。");string chosenDungeon=null;GUILayout.Label("使用する荷造り",header);GUILayout.BeginHorizontal();foreach(var loadout in meta.loadouts)if(GUILayout.Button(loadout.id==meta.selectedLoadoutId?$"● {loadout.name}":loadout.name,button,GUILayout.Height(52)))LoadoutSystem.Select(meta,loadout.id);GUILayout.EndHorizontal();var active=LoadoutSystem.Active(meta);GUILayout.Label($"{GameCatalog.Backpacks.First(x=>x.id==active.backpack).name}   配置{active.slots.Count}個   装備カード{active.deck.Count}枚",body);if(!string.IsNullOrEmpty(message)&&message.StartsWith("遠征開始エラー"))GUILayout.Label(message,new GUIStyle(hubLabel){normal={textColor=new Color(1f,.42f,.34f)}},GUILayout.Height(44));GUILayout.Space(16);GUILayout.Label("遠征先　―　カード全体をクリック",header);GUILayout.BeginHorizontal();for(int i=0;i<GameCatalog.Dungeons.Length;i++){var dungeon=GameCatalog.Dungeons[i];bool unlocked=i<meta.dungeonsUnlocked;Rect tile=GUILayoutUtility.GetRect(350,410,GUILayout.Width(350),GUILayout.Height(410));bool hover=unlocked&&tile.Contains(UnityEngine.Event.current.mousePosition);GUI.color=hover?Color.white:unlocked?new Color(.82f,.84f,.79f):new Color(.34f,.34f,.32f);GUI.DrawTexture(tile,Texture2D.whiteTexture);GUI.color=Color.white;Rect art=new(tile.x+8,tile.y+8,tile.width-16,235);DrawDungeonArt(art,dungeon.id);GUI.color=new Color(.012f,.018f,.014f,.94f);GUI.DrawTexture(new Rect(tile.x+8,tile.y+238,tile.width-16,tile.height-246),Texture2D.whiteTexture);GUI.color=Color.white;DrawOutline(tile,hover?gold:unlocked?new Color(.52f,.38f,.18f):new Color(.22f,.22f,.20f),hover?4:3);GUI.Label(new Rect(tile.x+20,tile.y+252,tile.width-40,31),dungeon.name,new GUIStyle(header){fontSize=19,alignment=TextAnchor.MiddleCenter,clipping=TextClipping.Clip});GUI.Label(new Rect(tile.x+24,tile.y+290,tile.width-48,45),dungeon.description,new GUIStyle(body){fontSize=12,alignment=TextAnchor.UpperCenter,wordWrap=true});GUI.Label(new Rect(tile.x+22,tile.yMax-58,tile.